using System;
using System.Data.SqlClient;

public class DatabaseConnectionHelper
{
    private readonly string _connectionString;

    public DatabaseConnectionHelper()
    {
        var server = Environment.GetEnvironmentVariable("DB_SERVER") ?? "localhost";
        var database = Environment.GetEnvironmentVariable("DB_DATABASE") ?? "HackathonDB";
        var userId = Environment.GetEnvironmentVariable("DB_USER_ID") ?? throw new InvalidOperationException("DB_USER_ID environment variable is required");
        var password = Environment.GetEnvironmentVariable("DB_PASSWORD") ?? throw new InvalidOperationException("DB_PASSWORD environment variable is required");

        _connectionString = $"Server={server};Database={database};User Id={userId};Password={password};";
    }

    public SqlConnection GetConnection()
    {
        return new SqlConnection(_connectionString);
    }

    public SqlConnection GetOpenConnection()
    {
        var connection = new SqlConnection(_connectionString);
        connection.Open();
        return connection;
    }

    public bool TestConnection()
    {
        try
        {
            using (var connection = GetOpenConnection())
            {
                return connection.State == System.Data.ConnectionState.Open;
            }
        }
        catch
        {
            return false;
        }
